input.command:
Set-Item WSMan:\localhost\Client\TrustedHosts -Value '26.168.226.201' -Concatenate -Force -ErrorAction SilentlyContinue
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential('26.168.226.201\usr1cv8', $sec)
try {
  Test-WSMan -ComputerName 26.168.226.201 -Credential $cred -Authentication Default -ErrorAction Stop | Out-Null
  Write-Host 'Test-WSMan OK with Default auth'
} catch {
  Write-Host "Default fail: $($_.Exception.Message)"
  try {
    Test-WSMan -ComputerName 26.168.226.201 -Credential $cred -Authentication Basic -ErrorAction Stop | Out-Null
    Write-Host 'Test-WSMan OK with Basic auth'
  } catch {
    Write-Host "Basic fail: $($_.Exception.Message)"
  }
}
# also try old password
$sec2 = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force
$cred2 = New-Object System.Management.Automation.PSCredential('26.168.226.201\usr1cv8', $sec2)
try {
  Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock { "$env:COMPUTERNAME / $env:USERNAME" } -ErrorAction Stop
} catch {
  Write-Host "Invoke 1111 Negotiate fail: $($_.Exception.Message)"
  try {
    Invoke-Command -ComputerName 26.168.226.201 -Credential $cred2 -Authentication Negotiate -ScriptBlock { "$env:COMPUTERNAME / $env:USERNAME" } -ErrorAction Stop
  } catch {
    Write-Host "Invoke usr1cv8 Negotiate fail: $($_.Exception.Message)"
  }
}

$ip='26.248.72.177'
$ping = Test-Connection $ip -Count 1 -Quiet -ErrorAction SilentlyContinue
$tcp = (Test-NetConnection $ip -Port 5985 -WarningAction SilentlyContinue).TcpTestSucceeded
Write-Host "ping=$ping tcp5985=$tcp"
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
try {
  $r = Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
    "$env:COMPUTERNAME / $env:USERNAME / $((Get-Date).ToString('yyyy-MM-dd HH:mm:ss'))"
  } -ErrorAction Stop
  Write-Host "OK: $r"
} catch {
  Write-Host "1111 fail: $($_.Exception.Message)"
  $sec2 = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force
  $cred2 = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec2)
  try {
    $r2 = Invoke-Command -ComputerName $ip -Credential $cred2 -Authentication Negotiate -ScriptBlock {
      "$env:COMPUTERNAME / $env:USERNAME"
    } -ErrorAction Stop
    Write-Host "OK with usr1cv8: $r2"
  } catch {
    Write-Host "usr1cv8 fail: $($_.Exception.Message)"
  }
}

$ip='26.248.72.177'
Write-Host '--- TrustedHosts ---'
(Get-Item WSMan:\localhost\Client\TrustedHosts).Value
Write-Host '--- AllowUnencrypted ---'
(Get-Item WSMan:\localhost\Client\AllowUnencrypted).Value
Write-Host '--- Test-WSMan no cred ---'
try { Test-WSMan $ip -ErrorAction Stop | Format-List * } catch { Write-Host $_.Exception.Message }

# try setting trustedhosts via winrm (may need admin)
winrm set winrm/config/client "@{TrustedHosts=`"$ip`"}" 2>&1
Write-Host "TrustedHosts after: $((Get-Item WSMan:\localhost\Client\TrustedHosts -EA SilentlyContinue).Value)"

$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
$credDot = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec)
$credBare = New-Object System.Management.Automation.PSCredential('usr1cv8', $sec)

foreach ($pair in @(
  @{n='neg+ip\user';c=$cred;a='Negotiate'},
  @{n='neg+.\user';c=$credDot;a='Negotiate'},
  @{n='neg+bare';c=$credBare;a='Negotiate'},
  @{n='basic+ip\user';c=$cred;a='Basic'},
  @{n='basic+bare';c=$credBare;a='Basic'}
)) {
  try {
    $r = Invoke-Command -ComputerName $ip -Credential $pair.c -Authentication $pair.a -ScriptBlock { "$env:COMPUTERNAME|$env:USERNAME" } -ErrorAction Stop
    Write-Host "SUCCESS $($pair.n): $r"
  } catch {
    $msg = $_.Exception.Message
    if ($msg.Length -gt 180) { $msg = $msg.Substring(0,180) }
    Write-Host "FAIL $($pair.n): $msg"
  }
}

$ip='26.248.72.177'
cmd /c "net use \\$ip\C$ /user:$ip\usr1cv8 1111" 2>&1
Write-Host "net use C$ exit=$LASTEXITCODE"
if (Test-Path "\\$ip\C$\Windows") { Write-Host 'C$ OK' } else { Write-Host 'C$ FAIL' }
# Try WMI
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
try {
  Get-WmiObject Win32_OperatingSystem -ComputerName $ip -Credential $cred -ErrorAction Stop | Select Caption, Version, CSName
} catch { Write-Host "WMI fail: $($_.Exception.Message)" }
try {
  Get-CimInstance Win32_OperatingSystem -ComputerName $ip -Credential $cred -ErrorAction Stop | Select Caption, Version, CSName
} catch { Write-Host "CIM fail: $($_.Exception.Message)" }

# Write a one-shot fix for TokenFilterPolicy via admin share + schtasks
$fixBat = @"
@echo off
reg add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System" /v LocalAccountTokenFilterPolicy /t REG_DWORD /d 1 /f
powershell -NoProfile -Command "Restart-Service WinRM -Force"
"@
$remotePath = "\\$ip\C$\Windows\Temp\fix_winrm_token.bat"
Set-Content -Path $remotePath -Value $fixBat -Encoding ASCII -Force
Write-Host "wrote $remotePath"
cmd /c "schtasks /s $ip /u $ip\usr1cv8 /p 1111 /create /tn FixWinRMToken /tr C:\Windows\Temp\fix_winrm_token.bat /sc once /st 00:00 /ru SYSTEM /f" 2>&1
cmd /c "schtasks /s $ip /u $ip\usr1cv8 /p 1111 /run /tn FixWinRMToken" 2>&1
Start-Sleep 3
cmd /c "schtasks /s $ip /u $ip\usr1cv8 /p 1111 /query /tn FixWinRMToken /v /fo LIST" 2>&1 | Select-String -Pattern 'Status|Last Run|Result|Task Name'

$ip='26.248.72.177'
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
try {
  Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock { "$env:COMPUTERNAME | $env:USERNAME | $(Get-Date -Format 'HH:mm:ss')" } -ErrorAction Stop
} catch {
  Write-Host "STILL BLOCKED: $($_.Exception.Message.Substring(0,[Math]::Min(120,$_.Exception.Message.Length)))"
}
